var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"唔……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L5_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그렇다, 방랑자여. <color=#ffd34c>이제까지</color>는 그래왔지.","JPN":"さよう、放浪者よ。<color=#ffd34c>今まで</color>はそうであった。","ENG":"Poor choice of words, Wayfarer. <color=#ffd34c>To this day</color>it has.","TWN":"沒錯，流浪者，<color=#ffd34c>一如往常</color>。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"현실의 공기를 마시며 지낸 자가, 왕께서 선별하신 자매들을 당해낼 수 있으리라 생각하느냐?","JPN":"現実の空気を吸い過ごした者が、王の選別された姉妹たちに勝てるとでも思ったか？","ENG":"Did you really think that one who relies on air in Normalside to breathe could ever overcome the sisters appointed by the queen?","TWN":"但你以為呼吸現世空氣的人，能夠招架王親自揀選的姊妹嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"아직……! 아직이다……!","JPN":"まだ……！　まだだ……！","ENG":"Not...! Not yet...!","TWN":"我……！我還可以……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나는, 아직……!","JPN":"我は、まだ……！","ENG":"I can still...!","TWN":"我還可以……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그런 피폐한 꼴로 자매들에게 저항한 것만은 칭찬해 주지.","JPN":"そのような疲弊した姿で姉妹たちに抗ったことは誉めてやろう。","ENG":"Your resistance despite your condition is commendable.","TWN":"光是看你用那副狼狽的模樣在抵抗，就很值得稱讚。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"허나 제 힘도 쓰지 못하고 녹슨 갑주에 의지하면서 왕의 이름을 능멸한 죄…….","JPN":"だが己の力も使えず、錆びた甲冑に頼りながら王の名を侮辱した罪……","ENG":"But the crime of sullying the queen’s name while relying on the power of a rusty old armor...","TWN":"不過無法發揮自己的能力，只靠那副破爛鎧甲，就想藐視王的罪……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"죽음을 면할 수 없겠구나.","JPN":"死は免れぬ。","ENG":"Your sentence can be nothing but death.","TWN":"我看是死罪難逃！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네 놈……. 솔리키타티오…….","JPN":"貴様……ソリキタティオ……","ENG":"Damn you... Sollicitatio...","TWN":"你這傢伙……索爾奇塔提奧……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"축복을 거부한 끝에 결국 진창에 처박히고 말았구나.","JPN":"祝福を拒んだ末に、結局ぬかるみにはまるか。","ENG":"You refused to receive the blessing and now you crawl in the mud.","TWN":"拒絕祝福，結果卻落得如此下場。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이제 끝이다. 마지막 순간까지 너의 불경함을…… ","JPN":"これでしまいだ。最後まで貴様の不敬を…… ","ENG":"It ends now. Right until your last moment, I couldn’t fix your... ","TWN":"都結束了，雖然到最後都無法矯正你的狂妄……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"처형의 검이 준비되었습니다, 자매님. 허락을.","JPN":"処刑の剣の準備ができました、お姉様。許可を。","ENG":"The execution sword has been prepared, sister. With your permission?","TWN":"行刑之劍已經備妥，等候您一聲令下。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"아니. 돌아가야 한다. 왕께서 부르셨으니.","JPN":"いや。帰らねばならぬ。王がお呼びだ。","ENG":"No. We must go back. The queen summons us.","TWN":"不，回去吧，王召喚我們。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"타기리온이……? 어째서…….","JPN":"タギリオンが……？　なぜ……","ENG":"Thagirion...? But why...","TWN":"塔基里翁……？怎麼會……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕의 자비를 감사히 여겨라. 방랑자여.","JPN":"王の慈悲に感謝しろ。放浪者よ。","ENG":"Rejoice, for the queen is merciful, Wayfarer.","TWN":"流浪者，你要感謝王的憐憫。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"아마도 너의 추태를 더 오래 감상하길 원하시나 보구나.","JPN":"おそらくお前の醜態をもっとご覧になりたいのであろう。","ENG":"Perhaps your indecent behavior is found amusing.","TWN":"可能是王想要再多欣賞一下你的醜態吧？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINISTRA_CORRUPT_DREAD_NULL","text":{"KOREA":"후훗. 우리 귀여운 동생. 이제 괜찮아. 방해꾼은 우릴 더 이상 건드리지 못해.","JPN":"ふふっ。私のかわいい妹よ。もう大丈夫だ。邪魔者はもう私たちに手を出せない。","ENG":"Fuu fuu. My cute little sister. Everything is okay now. That nasty little rabble rouser won’t be able to bother us any more.","TWN":"呵呵，我可愛的妹妹，沒事了，再也沒有人會來打擾我們。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……그래. 이제 당해낼 수 없는가.","JPN":"……そうか。もう敵うことができぬのか。","ENG":"...Very well. It appears I cannot resist any longer.","TWN":"……是嗎？我現在招架不住嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이제 더 이상은…….","JPN":"もうこれ以上は……","ENG":"I can no longer...","TWN":"再也……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"알리지 말라니! 이런 만행을 저질러 놓고 어찌 반성하는 기색도 보이지 않는단 말인가?","JPN":"知らせるなと！？　あんな蛮行を犯しておいて、なぜ反省する気配すら見せないのか？","ENG":"Answer me! How can you show no remorse after committing such an atrocity!","TWN":"怎麼可以不說！犯下這種暴行，你完全都沒有悔意嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"예하. 예하께오서 그 아이와 함께 마왕을 격퇴한 업적은 잘 알고 있습니다.","JPN":"猊下。猊下があの子と一緒に魔王を撃退された功績はよく存じております。","ENG":"Your Eminence. Your achievement in defeating the Demon Lord with that child’s help was extraordinary.","TWN":"主教，我很清楚您和那孩子一起擊退魔王的事蹟。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"허나 예하께서 원정을 떠나신 동안 역병으로부터 이 세상을…….","JPN":"ですが、猊下が遠征に出られている間、疫病からこの世界を……","ENG":"But while Eminence was away from the campaign, the plague ravaged this world...","TWN":"但您想想，當您去遠征時，我們如何能保護這個世界……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>엘리시온</color>을 어떻게 지킬 수 있었는지 헤아려 주시지요.","JPN":"<color=#ffd34c>エリシオン</color>をどうやって守ることができたかをご賢察ください。","ENG":"We had to consider how to best protect <color=#ffd34c>Elysion</color>.","TWN":"保護<color=#ffd34c>艾利森</color>不受到瘟疫的攻擊？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……멘탈 프린팅이 이런 끔찍한 짓인 줄 알았더라면 내 결코 용인하지 않았을 것이다.","JPN":"……メンタル・プリンティングがこのように残酷なことであると知っていたら、私は決して許していなかった。","ENG":"...If I had known Mental Printing was so terrible, I would never have approved of it.","TWN":"……要是我知道是智力複印，這麼可怕的行為，我是絕對不會允許的！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"성인의 인격을 주입해 <color=#ffd34c>성흔</color>을 각성시킨다고? 당하는 이들은 죽는 셈이나 다름없지 않은가!","JPN":"聖人の人格を注入し、<color=#ffd34c>聖痕</color>を覚醒させるだと？　注入された者は死ぬも同然ではないか！","ENG":"You’re implanting a Saint’s consciousness to awaken a <color=#ffd34c>Stigmata</color>? The original mind will perish!","TWN":"是植入聖人的人格使<color=#ffd34c>聖痕</color>覺醒對吧？那被植入的人與死有什麼兩樣？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"희생을 통해 엘리시온에 기여하는 바이니, 기쁘게 받아들여야지요.","JPN":"犠牲によりエリシオンに貢献するのですから、ありがたく受け入れるべきです。","ENG":"It is a great sacrifice for the greater good of Elysion, they should be honored.","TWN":"藉由那些犧牲來保住艾利森，您應該要開心接受不是嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그걸…… 그걸 지금 말이라고 하는 건가?","JPN":"それを……それを本気で言っているのか？","ENG":"...Is that what you call it now?","TWN":"你……你現在說的還是人話嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"어차피 실험체로 사용한 것은 수용소에 가둬 둔 이교도와 배교자들뿐이랍니다.","JPN":"どうせ実験体に使われたのは、収容所に閉じ込めておいた異教徒と背教者だけです。","ENG":"In any case, only pagans and apostates in prison were used as test subjects.","TWN":"反正拿來當作實驗體的，都是那些關在收容所裡的異教徒和判教者。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"불완전한 상태로도 성흔의 획득에 성공하였습니다.","JPN":"不完全な状態でも聖痕を獲得できました。","ENG":"Even though they never reached a complete state, the acquisition of a Stigmata was still successful.","TWN":"就算在還不完整的狀態下，依然成功獲得聖痕。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"이제 저희가 원하는 성흔을 얻는 방법만 완성하면, 엘리시온은 영원토록 건재할 것입니다.","JPN":"あとは私たちの望む聖痕を得る方法さえ完成すれば、エリシオンは永遠に健在するでしょう。","ENG":"Now that the ability to obtain a Stigmata has been perfected, Elysion will live forever on.","TWN":"現在只要我們得到想要的聖痕，艾利森便將永遠存在。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"이를테면, 예하께서 받은 성흔 말입니다.","JPN":"例えば、猊下が譲り受けた聖痕のようにです。","ENG":"For instance, the Stigmata received by Eminence.","TWN":"也就是主教獲得的聖痕。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"상상해 보시죠. 예하와 같은 자들이 부대를 이루고 군단을 형성한 광경을.","JPN":"想像してみてください。猊下のような者たちが部隊を成し、軍団を形成した光景を。","ENG":"Imagine the sight of an army made up of those just like Eminence.","TWN":"您試想一下，像您一樣的人組成部隊後形成軍團的景象。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"아아……. 이것만은 앞이 보이지 않는다는 사실이 원망스럽군요. 그와 같은 광경을 이루어도 제 눈에 담을 수가 없다니.","JPN":"ああ……これだけは目が見えないという事実が悔しいです。そのような光景が実現になっても私の目で見ることができないなんて。","ENG":"Ahhh... To be able to see such a scene with one’s own eyes. I wish to be able to see that.","TWN":"哇……光想就覺得很遺憾，為什麼我的眼睛看不見，我竟然無法親眼見到如此棒的景象。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……미쳐 버렸구나. 최고 지휘자.","JPN":"……狂ったな。首席指揮者。","ENG":"...Madness has taken you. Maestra Nequitia.","TWN":"……你瘋了，首席指揮家。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"미친 것은 당신이지 않습니까?","JPN":"狂ったのはあなたではありませんか。","ENG":"Rather, aren’t you the one that’s mad?","TWN":"瘋的應該是您吧？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"뭐라……? 지금 뭐라 하였느냐?","JPN":"何……？　今、何と？","ENG":"What...? What is the meaning of your words?","TWN":"什麼……？你說什麼？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"예하야말로 그 이교도 아이에게 너무 정을 붙이신 것 아닌지요.","JPN":"猊下こそあの異教徒の子に情が移りすぎではないのですか？","ENG":"For example, you are far too attached to that pagan child. Are you not?","TWN":"主教才是對那異教徒孩子放太多感情吧？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"엘리시온 교단은 암흑 속에서 태어난 저를 이끌어 주었습니다. 교단을 위해서라면 무슨 짓이든 할 수 있어요.","JPN":"エリシオン教団は暗黒の中で生まれた私を導いてくれました。教団のためならなんでもできます。","ENG":"Ever since I was born in darkness, it was the Elysion Order that has guided my hand. There is nothing I would not do for it.","TWN":"艾利森教團帶領著從黑暗裡出生的我，為了教團，我可以赴湯蹈火在所不辭。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"하지만 예하는 어떠십니까? 그깟 어린 이교도와의 약속 때문에 정세를 외면하고 계시지 않습니까?","JPN":"ですが猊下はいかがですか？　あんな異教徒の子との約束のために情勢から目を背けているではないですか。","ENG":"But what of you, Eminence? Have you not turned a blind eye to the situation because of your promise with that pagan?","TWN":"但主教呢？只因為和那個異教徒的約定，就可以不顧全大局？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"타기리온은 쓰러졌어! 마왕은 이제 없고 세상은 안전하다!","JPN":"タギリオンは倒れた！　もう魔王はおらず、世の中は安全なのだ！","ENG":"Thagirion is no more! The Demon Lord was vanquished and the world is safe now!","TWN":"塔基里翁已經不在了！之後再也沒有魔王，世界是安全的！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"정녕 그러하다고 여기시나요? 아니면 그러길 바라시는 겁니까?","JPN":"本当にそう思っていらっしゃるのですか？　それともそうであって欲しいのですか？","ENG":"Is that really the truth of the matter? Or is it simply only what you wish were true?","TWN":"您真的這麼認為嗎？還是這只是您的奢望？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"동쪽에서 새로운 역병이 창궐하였다는 소문이 들리더군요. 또 지난번과 같은 혹독한 시련의 시기가 펼쳐지겠지요.","JPN":"東で新しい疫病が猛威をふるっているとの噂です。またこの前のように過酷な試練が訪れるでしょう。","ENG":"Rumors are rising that a plague has erupted in the east. New trials to be undertaken, just as before.","TWN":"您應該有聽說，東邊又有新的瘟疫肆虐吧？看來像上次那樣嚴峻的時期又將到來。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……이 일은 추기경들을 소집하여 엄히 논하도록 하겠다.","JPN":"……このことは枢機卿を招集し、厳密に検討しよう。","ENG":"...I will gather the cardinals to discuss how to handle this matter.","TWN":"……關於這件事，我會召集樞機主教們一起討論。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"처벌을 피할 수 없을 것이다. 겸허히 받아들이도록.","JPN":"処罰は避けられまい。謙虚に受け入れるように。","ENG":"Punishment will not be avoided. Receive it with honor.","TWN":"懲罰是無可避免的，你就虛心受罰吧！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"처벌을 내리시겠다면 피하지는 않겠습니다만, 예하.","JPN":"処罰するというのなら受けましょう、猊下。","ENG":"If I must be punished so be it, but Eminence...","TWN":"若真要罰我，我自然是不會躲避。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"부디 무엇이 교단을, 나아가 이 세계를 위한 선택인지 헤아려 주시길.","JPN":"ですが、何が教団の、そしてこの世界のための選択であるか、どうかご賢察ください。","ENG":"What I did was done for the greater good of our Order, and furthermore for the world.","TWN":"但請主教務必三思，究竟什麼才是對教團、對這個世界最好的選擇。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"나는 항상 적막한 후회의 길을 걷고 있으니.","JPN":"我は常に寂寞たる後悔の道を歩んでいる。","ENG":"I'm the one always walking on the silent path of regret.","TWN":"我總是走在淒涼的悔恨之路上。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"이 깊고 어두운 수렁 속에서 내게 주어진 불씨는…… 오직 후회뿐이로다.","JPN":"この深く暗い泥沼のなかで我に与えられた火種は……ただ後悔のみ。","ENG":"In this deep and dark pit, the only flicker of light... is that of regret.","TWN":"在這深淵泥沼裡，我得到的就只有悔恨。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};